const input = $input.first().json;

// Handle no-match-found case
if (!input.submission_id) {
  return [{
    json: {
      found: false,
      error: 'Submission not found',
    },
  }];
}

const status = input.status || 'data received';

// Parse the content_data JSON string if present
let contentData = null;
if (input.content_data) {
  try {
    contentData = typeof input.content_data === 'string' 
      ? JSON.parse(input.content_data) 
      : input.content_data;
  } catch (e) {
    // If JSON parsing fails, return raw string
    contentData = input.content_data;
  }
}

// Parse spec_data and image_data similarly (for completeness/debugging)
let specData = null;
if (input.spec_data) {
  try {
    specData = typeof input.spec_data === 'string' 
      ? JSON.parse(input.spec_data) 
      : input.spec_data;
  } catch (e) {
    specData = input.spec_data;
  }
}

let imageData = null;
if (input.image_data) {
  try {
    imageData = typeof input.image_data === 'string' 
      ? JSON.parse(input.image_data) 
      : input.image_data;
  } catch (e) {
    imageData = input.image_data;
  }
}

// Status order for the progress checklist
const statusOrder = ['data received', 'specs extracted', 'images analyzed', 'content drafted'];
const currentIndex = statusOrder.indexOf(status);

return [{
  json: {
    found: true,
    submissionId: input.submission_id,
    receivedAt: input.received_at,
    skuId: input.sku_id,
    category: input.category,
    brand: input.brand,
    notes: input.notes,
    fileCount: input.file_count,
    status: status,
    statusIndex: currentIndex,
    isComplete: status === 'content drafted',
    specData: specData,
    imageData: imageData,
    contentData: contentData,
  },
}];
